import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/modules/base_classes/cellular_module_base.dart';

/// Shared public-behavior contract for generated cellular/stochastic modules.
///
/// Owns smoke-test expectations common to every generated cellular module test.
/// Exposes one contract function. Must not know about individual module classes,
/// shader implementation details, UI, persistence, or app orchestration.
void expectCellularModuleSmokeContract({
  required String moduleName,
  required CellularModule Function() buildModule,
  required String expectedId,
  required String expectedShader,
}) {
  test('$moduleName instantiates', () {
    final m = buildModule();
    expect(m.id, expectedId);
    expect(m.shader, expectedShader);
  });

  test('$moduleName presets are well-formed', () {
    final m = buildModule();
    expect(m.presets, isNotEmpty);
    for (final p in m.presets) {
      final preset = p as dynamic;
      expect(preset.id, isNotEmpty);
      expect(preset.name, isNotEmpty);
    }
  });

  test('$moduleName metadata is consistent', () {
    final m = buildModule();
    final metadata = m.metadata as dynamic;
    expect(metadata.id, m.id);
  });
}

